// This file is generated by scripts/build-frontend.mjs. Do not edit by hand.
const TrpgTemplates = (() => {
    const templates: Record<string, string> = {
    "chat-command-palette-item": "<button type=\"button\" class=\"list-group-item list-group-item-action command-palette-item\" data-command=\"{{ commandName }}\">\n    <span>\n        <strong>{{ usage }}</strong>\n        <span class=\"text-muted ms-2\">{{ description }}</span>\n    </span>\n    {{{ hintHtml }}}\n</button>",
    "chat-command-palette-hint": "<small class=\"command-palette-hint\">{{ hint }}</small>",
    "chat-message": "<div class=\"message-avatar\">\n    <img src=\"{{ avatarSrc }}\" alt=\"{{ sender }}\">\n</div>\n<div class=\"message-content-container\">\n    <div class=\"message-header\">\n        <span class=\"message-sender\">{{ sender }}</span>\n        <span class=\"message-time\">{{ displayTime }}</span>\n    </div>\n    <div class=\"message-content markdown-body\">{{{ contentHtml }}}</div>\n    {{{ processingHtml }}}\n</div>",
    "chat-processing-time": "<div class=\"processing-time\">{{ text }}</div>",
    "chat-welcome": "<div class=\"welcome-text\">请选择或创建一个房间开始游戏。</div>",
    "cookie-consent-banner": "<div class=\"cookie-consent-text\">\n    本应用使用必要登录 Cookie 保持会话；可选 Cookie 用于记住上次用户名和房间偏好。\n</div>\n<div class=\"cookie-consent-actions\">\n    <button type=\"button\" class=\"btn btn-sm btn-outline-secondary\" id=\"declineCookieConsent\">仅必要 Cookie</button>\n    <button type=\"button\" class=\"btn btn-sm btn-primary\" id=\"acceptCookieConsent\">同意</button>\n</div>",
    "select-placeholder-option": "<option value=\"\">{{ label }}</option>",
    "room-empty-list": "<div class=\"text-center text-muted py-5\">暂无房间，请创建房间或输入房间码加入。</div>",
    "room-card-grid": "<div class=\"row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4\">\n    {{{ cardsHtml }}}\n</div>",
    "room-card": "<div class=\"col\">\n    <div class=\"card save-card h-100 {{ activeClass }}\" data-room-id=\"{{ roomId }}\">\n        {{{ activeHeaderHtml }}}\n        <div class=\"card-body\">\n            <h5 class=\"card-title\">{{ name }}</h5>\n            <p class=\"card-text mb-2\">\n                <small class=\"text-muted\">房间码：{{ roomCode }}</small><br>\n                <small class=\"text-muted\">剧本：{{ scenarioTitle }}</small><br>\n                <small class=\"text-muted\">成员：{{ members }}</small>\n            </p>\n        </div>\n        <div class=\"card-footer bg-transparent border-0\">\n            <button class=\"btn btn-primary w-100 view-room-btn\">{{ actionLabel }}</button>\n        </div>\n    </div>\n</div>",
    "room-active-header": "<div class=\"card-header bg-primary text-white text-center py-2\"><small><i class=\"fa fa-check-circle\"></i> 当前房间</small></div>",
    "room-character-empty": "<div class=\"text-muted\">暂无参与玩家</div>",
    "room-character-binding": "<div class=\"room-character-binding border rounded p-3 mb-3\">\n    <div class=\"d-flex justify-content-between align-items-start gap-3\">\n        <div>\n            <div class=\"fw-bold\">{{ username }}</div>\n            <div class=\"text-muted\">{{ cardName }}</div>\n        </div>\n        <div class=\"text-end\">\n            <span class=\"badge bg-primary\">HP {{ currentHp }} / {{ maxHp }}</span>\n            <span class=\"badge bg-secondary\">San {{ currentSan }} / {{ maxSan }}</span>\n        </div>\n    </div>\n    <div class=\"row mt-3\">\n        <div class=\"col-md-6\">\n            <h6>生命值/受伤记录</h6>\n            {{{ injuryRecordsHtml }}}\n        </div>\n        <div class=\"col-md-6\">\n            <h6>San 值鉴定和损失记录</h6>\n            {{{ sanityRecordsHtml }}}\n        </div>\n    </div>\n</div>",
    "room-record-empty": "<div class=\"text-muted small\">暂无记录</div>",
    "room-record-list": "<div class=\"list-group\">{{{ recordsHtml }}}</div>",
    "room-record-item": "<div class=\"list-group-item d-flex justify-content-between gap-2\">\n    <div>\n        <div>{{ typeLabel }} {{ value }}</div>\n        <small class=\"text-muted\">{{ reason }} · {{ createdAt }}</small>\n    </div>\n    {{{ deleteButtonHtml }}}\n</div>",
    "room-record-delete-button": "<button type=\"button\" class=\"btn btn-sm btn-outline-danger\" data-record-id=\"{{ recordId }}\">删除</button>",
    "room-node-empty": "<div class=\"text-center text-muted py-3\">暂无回档节点</div>",
    "room-node-list": "<div class=\"list-group\">{{{ nodesHtml }}}</div>",
    "room-node-item": "<div class=\"list-group-item list-group-item-action d-flex justify-content-between align-items-center\">\n    <div>\n        <h6 class=\"mb-1\">回档节点</h6>\n        <small class=\"text-muted\">创建时间：{{ createdAt }} | 消息数：{{ messageCount }}</small>\n    </div>\n    <div>\n        <button class=\"btn btn-sm btn-secondary preview-node-btn me-2\" data-node-filename=\"{{ filename }}\">预览</button>\n        <button class=\"btn btn-sm btn-primary load-node-btn me-2\" data-node-filename=\"{{ filename }}\">回档</button>\n        <button class=\"btn btn-sm btn-danger delete-node-btn\" data-node-filename=\"{{ filename }}\">删除</button>\n    </div>\n</div>",
    "room-preview-list": "<div class=\"preview-messages\">\n    {{{ messagesHtml }}}\n</div>",
    "room-preview-message": "<div class=\"preview-message mb-3 p-3 border rounded bg-light\">\n    <div class=\"fw-bold text-primary mb-2\">{{ sender }}</div>\n    <div class=\"markdown-body\">{{ content }}</div>\n</div>",
    "scenario-card": "<img src=\"{{ coverPath }}\" alt=\"{{ title }}\" onerror=\"this.src='{{ fallbackCover }}'\">\n<div class=\"scenario-card-body\">\n    <div class=\"scenario-card-title\">{{ title }}</div>\n    <p>作者: {{ author }}</p>\n    <p>推荐人数: {{ playerCount }}</p>\n    <div class=\"scenario-card-actions\">\n        <button class=\"btn btn-sm btn-primary preview-scenario\" data-id=\"{{ id }}\">预览</button>\n        <button class=\"btn btn-sm btn-secondary edit-scenario\" data-id=\"{{ id }}\">编辑</button>\n        <button class=\"btn btn-sm btn-danger delete-scenario\" data-id=\"{{ id }}\">删除</button>\n    </div>\n</div>",
    "scenario-preview-content": "<h3>{{ title }}</h3>\n<p><strong>作者:</strong> {{ author }}</p>\n<p><strong>推荐人数:</strong> {{ playerCount }}</p>\n<p><strong>备注:</strong> {{ notes }}</p>\n<p><strong>背景/引入:</strong> {{ background }}</p>\n<p><strong>游戏准备:</strong> {{ preparation }}</p>\n<h4>场景</h4>\n{{{ scenesHtml }}}\n<h4>结局</h4>\n{{{ endingsHtml }}}",
    "scenario-preview-segment": "<div class=\"mb-3\">\n    <h5>{{ label }} {{ id }}</h5>\n    <p>{{ content }}</p>\n    {{{ markerHtml }}}\n</div>",
    "scenario-preview-marker": "<p><strong>标记:</strong> {{ marker }}</p>",
    "scenario-preview-modal": "<div class=\"modal-dialog modal-lg\">\n    <div class=\"modal-content\">\n        <div class=\"modal-header\">\n            <h5 class=\"modal-title\">剧本预览</h5>\n            <button type=\"button\" class=\"btn-close\" data-bs-dismiss=\"modal\" aria-label=\"Close\"></button>\n        </div>\n        <div class=\"modal-body\">{{{ previewContent }}}</div>\n        <div class=\"modal-footer\">\n            <button type=\"button\" class=\"btn btn-secondary\" data-bs-dismiss=\"modal\">关闭</button>\n        </div>\n    </div>\n</div>",
    "scenario-segment-editor": "<div class=\"{{ className }} mb-3 p-3 border rounded\">\n    <div class=\"d-flex justify-content-between align-items-center mb-2\">\n        <h6>{{ label }} {{ index }}</h6>\n        <button type=\"button\" class=\"btn btn-sm btn-danger {{ removeClass }}\">删除</button>\n    </div>\n    <div class=\"form-group\">\n        <label>{{ label }}内容</label>\n        <textarea class=\"form-control\" rows=\"3\">{{ content }}</textarea>\n    </div>\n    <div class=\"form-group mt-2\">\n        <label>{{ label }}标记</label>\n        <textarea class=\"form-control\" rows=\"2\" placeholder=\"AI总结内容将显示在这里\">{{ marker }}</textarea>\n    </div>\n</div>",
    "notification-message": "<div class=\"notification {{ variant }}\">{{ message }}</div>"
};

    function escapeHtml(value: unknown): string {
        return String(value ?? "")
            .replace(/&/g, "&amp;")
            .replace(/</g, "&lt;")
            .replace(/>/g, "&gt;")
            .replace(/"/g, "&quot;")
            .replace(/'/g, "&#039;");
    }

    function render(templateId: string, values: Record<string, unknown> = {}): string {
        const template = templates[templateId];
        if (template === undefined) {
            throw new Error(`Unknown frontend template: ${templateId}`);
        }
        return template
            .replace(/\{\{\{\s*([\w.]+)\s*\}\}\}/g, (_, key: string) => String(values[key] ?? ""))
            .replace(/\{\{\s*([\w.]+)\s*\}\}/g, (_, key: string) => escapeHtml(values[key]));
    }

    return { render, escapeHtml };
})();

window.TrpgTemplates = TrpgTemplates;
